INSERT INTO public.pe_narratives (pe_id, fiscal_year, mission_description, justification, accomplishments, planned_program, performance_metrics, other_program_funding, raw_text, content_hash, section_hashes, source_pdf, source_page, ingested_at) VALUES ($$0604129A$$, 2027, $$This Program Element (PE) implements Executive Order (EO) 14299 - Deploying Advanced Nuclear Reactor Technologies for National Security - The United States
faces a critical national security imperative to ensure a resilient, secure, and reliable energy supply for critical defense facilities designated under section 824o-1(c)
of title 16, United States Code, and other mission capability resources. It is the policy of the United States to ensure the rapid development, deployment, and use of
advanced nuclear technologies to support national security objectives, such as the protection and operation of critical infrastructure, critical defense facilities, and other
mission capability resources. The Secretary of the Army serves as the Department of War (DoW) Executive Agent (EA) for both installation and operational nuclear
energy, will lead and begin planning for deployment of Microreactor Power Plants (MPPs). With this funding, the United States will for the first time deploy MPPs at
scale, turning the nation into the global leader in installation and operational nuclear energy.$$, $$As designated in the EO 14299, the Army serves as the DoW Executive Agent (EA) for installation and operational nuclear energy. The Assistant Secretary of the Army
for Installations, Energy and Environment (ASA-IEE) executes the responsibilities necessary using the existing EA Agreement on behalf of all of the Services, including
expanding the Army Nuclear Energy (NEO) Office and Janus Program Office to lead and support the EA office functions under the ASA-IEE, establishing and executing
the program of record for both installation and operational nuclear energy. The NEO/Janus (Project) Program Office will work with Department of Energy (DOE) and the
Services to establish deployment models, phased funding allocations, milestone payments proposals to deploy Contractor Owned Contractor Operated (COCO) and
Army Reactor Regulatory Office (ARRO) regulated MPPs. All support rendered by DoW will be structured in such a way as to comply with Federal Support Restriction
(FSR) limitations.

 Funding supports all aspects of Executive Agency responsibilities including all Army Regulatory Permitting and oversight and implement Executive Order (EO) 14299.

